import { spawn, type ChildProcess } from "child_process";
import {
  createPublicClient,
  createWalletClient,
  createTestClient,
  http,
  parseEther,
} from "viem";
import { privateKeyToAccount } from "viem/accounts";
import { foundry } from "viem/chains";
import { DONATION_POOL_ABI } from "../src/abi/donationPool.js";

export const ANVIL_URL = "http://127.0.0.1:8545";
export const MIN_DONATION = parseEther("0.001");

// Anvil default funded accounts
export const OWNER_PRIVATE_KEY =
  "0xac0974bec39a17e36ba4a6b4d238ff944bacb478cbed5efcae784d7bf4f2ff80";
export const DONOR_PRIVATE_KEY =
  "0x59c6995e998f97a5a0044966f0945389dc9e86dae88c7a8412f4603b6b78690d";
export const NON_OWNER_PRIVATE_KEY =
  "0x5de4111afa1a4b94908f83103eb1f1706367c2e68ca870fc3fb9a804cdab365a";

export const ownerAccount = privateKeyToAccount(OWNER_PRIVATE_KEY);
export const donorAccount = privateKeyToAccount(DONOR_PRIVATE_KEY);
export const nonOwnerAccount = privateKeyToAccount(NON_OWNER_PRIVATE_KEY);

let anvilProcess: ChildProcess | null = null;

export async function startAnvil(): Promise<void> {
  anvilProcess = spawn("anvil", ["--port", "8545", "--silent"], {
    stdio: "pipe",
  });

  await new Promise<void>((resolve, reject) => {
    const timeout = setTimeout(
      () => reject(new Error("Anvil startup timed out")),
      10000,
    );

    const check = async () => {
      try {
        const client = createPublicClient({
          chain: foundry,
          transport: http(ANVIL_URL),
        });
        await client.getBlockNumber();
        clearTimeout(timeout);
        resolve();
      } catch {
        setTimeout(check, 100);
      }
    };
    check();
  });
}

export async function stopAnvil(): Promise<void> {
  if (anvilProcess) {
    anvilProcess.kill();
    anvilProcess = null;
    await new Promise((r) => setTimeout(r, 200));
  }
}

export function makeAnvilClients() {
  const chain = foundry;
  const transport = http(ANVIL_URL);

  const publicClient = createPublicClient({ chain, transport });
  const testClient = createTestClient({ chain, transport, mode: "anvil" });
  const ownerWallet = createWalletClient({
    chain,
    transport,
    account: ownerAccount,
  });
  const donorWallet = createWalletClient({
    chain,
    transport,
    account: donorAccount,
  });
  const nonOwnerWallet = createWalletClient({
    chain,
    transport,
    account: nonOwnerAccount,
  });

  return { publicClient, testClient, ownerWallet, donorWallet, nonOwnerWallet };
}

export async function deployDonationPool(): Promise<`0x${string}`> {
  const { ownerWallet, publicClient } = makeAnvilClients();

  const hash = await ownerWallet.deployContract({
    abi: DONATION_POOL_ABI,
    bytecode: DONATION_POOL_BYTECODE,
    args: [MIN_DONATION],
  });

  const receipt = await publicClient.waitForTransactionReceipt({ hash });
  if (!receipt.contractAddress) throw new Error("Deploy failed — no address");
  return receipt.contractAddress;
}

// Bytecode compiled from contracts/out/DonationPool.sol/DonationPool.json
// Run `pnpm sync-abi` after any contract change to regenerate
export const DONATION_POOL_BYTECODE =
  "" as `0x${string}`;
